import { isValidElement } from 'react';

/** @typedef {import ('react').FunctionComponentElement<unknown>} ThumbnailComponent */
/** @typedef {import ('../..').ListItemProps['leftContent']} LeftContent */

/**
 * @param {LeftContent} leftContent
 * @returns {boolean}
 */
export const hasImage = (leftContent) => {
  const isThumbnail = isValidElement(leftContent)
    && /** @type {ThumbnailComponent} */ (leftContent)?.type?.displayName === 'Thumbnail';
  const isImage = typeof /** @type {import("../..").ImageContent} */(leftContent)?.src === 'string';

  return !!(isThumbnail || isImage);
};
